import{_ as h,o as t,c as a,ag as i}from"./chunks/framework.CvgP6Fyv.js";const u=JSON.parse('{"title":"Hướng dẫn Tổng quan (User Guide)","description":"Cẩm nang hướng dẫn tạo Data, vận hành và xử lý lỗi phần mềm HappyAgent dành cho Non-tech","frontmatter":{"title":"Hướng dẫn Tổng quan (User Guide)","description":"Cẩm nang hướng dẫn tạo Data, vận hành và xử lý lỗi phần mềm HappyAgent dành cho Non-tech","robots":"index, follow"},"headers":[],"relativePath":"sop/user-guide.md","filePath":"sop/user-guide.md"}'),o={name:"sop/user-guide.md"};function e(c,n,g,r,l,p){return t(),a("div",null,[...n[0]||(n[0]=[i('<h1 id="📖-huong-dan-van-hanh-happyagent-danh-cho-non-tech" tabindex="-1">📖 Hướng dẫn Vận hành HappyAgent (Dành cho Non-Tech) <a class="header-anchor" href="#📖-huong-dan-van-hanh-happyagent-danh-cho-non-tech" aria-label="Permalink to &quot;📖 Hướng dẫn Vận hành HappyAgent (Dành cho Non-Tech)&quot;">​</a></h1><blockquote><p><strong>&quot;Trăm KOC, một cú click&quot;</strong> Bạn không cần phải biết lập trình hay rành công nghệ để vận hành HappyAgent. Chúng tôi hiểu rằng thứ bạn cần là <strong>Thực thi nhanh, ổn định và tự động</strong>. HappyAgent đã gánh phần kỹ thuật phức tạp (ẩn danh IP, vượt check captcha, tự học lại khi TikTok đổi giao diện), việc của bạn chỉ là: Giao việc cho nó và theo dõi.</p></blockquote><hr><h2 id="🧐-happyagent-giai-quyet-van-đe-gi" tabindex="-1">🧐 HappyAgent giải quyết vấn đề gì? <a class="header-anchor" href="#🧐-happyagent-giai-quyet-van-đe-gi" aria-label="Permalink to &quot;🧐 HappyAgent giải quyết vấn đề gì?&quot;">​</a></h2><p>Khi vận hành Affiliate hay tìm kiếm KOC trên hệ thống, việc nhắn tin cho hàng trăm KOC một cách thủ công vừa tốn thời gian, vừa dễ bị hệ thống đánh dấu là &quot;Hành vi bất thường&quot; (Spam).</p><p>HappyAgent đóng vai trò như một <strong>Trợ lý Ảo độc lập</strong>:</p><ol><li><strong>Tự động đăng nhập</strong> an toàn vào các tài khoản của bạn (mà không bị quét là Robot).</li><li>Tự động đọc danh sách KOC bạn đã lưu trong File dữ liệu.</li><li>Liên hệ, gửi tin nhắn theo các <strong>Thông điệp mẫu</strong> đã được cá nhân hóa.</li><li>Tự ghi nhận báo cáo xem tin nhắn nào đã gửi, tin nào thất bại.</li></ol><hr><h2 id="📦-3-thanh-phan-chinh-ban-can-biet" tabindex="-1">📦 3 Thành phần chính bạn cần biết <a class="header-anchor" href="#📦-3-thanh-phan-chinh-ban-can-biet" aria-label="Permalink to &quot;📦 3 Thành phần chính bạn cần biết&quot;">​</a></h2><p>Không cần nhìn mã code, bạn chỉ thao tác với 3 tệp dữ liệu quen thuộc như dùng Excel hay Word:</p><ol><li><strong>📁 Danh sách Khách hàng (<code>creators.csv</code>)</strong>: File danh sách KOC/Creator mà bạn muốn liên hệ. Mở nó bằng Excel hoặc thẻ Google Sheets quen thuộc.</li><li><strong>📝 Mẫu tin nhắn (<code>message-template.json</code>)</strong>: Kịch bản chat của bạn. Bạn có thể sửa &quot;Nội dung chào hỏi&quot;, &quot;Links đính kèm&quot; theo ý muốn.</li><li><strong>🔑 Hồ sơ Trình duyệt (<code>profiles.json</code>)</strong>: Chứa &quot;CMND ảo&quot; của mỗi nick đăng nhập để an toàn nhất.</li></ol><hr><h2 id="❓-cau-hoi-thuong-gap-q-a" tabindex="-1">❓ Câu Hỏi Thường Gặp (Q&amp;A) <a class="header-anchor" href="#❓-cau-hoi-thuong-gap-q-a" aria-label="Permalink to &quot;❓ Câu Hỏi Thường Gặp (Q&amp;A)&quot;">​</a></h2><h3 id="_1-neu-toi-vo-tinh-nhap-sai-file-thi-sao" tabindex="-1">1. Nếu tôi vô tình nhập sai file thì sao? <a class="header-anchor" href="#_1-neu-toi-vo-tinh-nhap-sai-file-thi-sao" aria-label="Permalink to &quot;1. Nếu tôi vô tình nhập sai file thì sao?&quot;">​</a></h3><p>Đừng lo! HappyAgent có chế độ kiểm tra lỗi ngay khi bạn bấm chạy. Nó sẽ nhắc nhở bằng tiếng Việt rõ ràng nếu bạn lỡ xóa nhầm dấu phẩy hay sai cột Excel.</p><h3 id="_2-luc-no-chay-tai-khoan-co-bi-khoa-khong" tabindex="-1">2. Lúc nó chạy, tài khoản có bị khóa không? <a class="header-anchor" href="#_2-luc-no-chay-tai-khoan-co-bi-khoa-khong" aria-label="Permalink to &quot;2. Lúc nó chạy, tài khoản có bị khóa không?&quot;">​</a></h3><p>HappyAgent dùng công nghệ <strong>CloakBrowser Stealth</strong> có thiết lập cơ chế bấm ngẫu nhiên theo nhịp điệu của con người (Humanize). Mỗi tài khoản sẽ có một dấu vân tay (Fingerprint) riêng trên Internet. Hãy tưởng tượng 5 tài khoản ở 5 máy tính ở tỉnh thành khác nhau đang chạy, TikTok hoàn toàn không biết!</p><h3 id="_3-đang-chay-thi-no-bi-vang-ra-crash" tabindex="-1">3. Đang chạy thì nó bị văng ra (Crash)? <a class="header-anchor" href="#_3-đang-chay-thi-no-bi-vang-ra-crash" aria-label="Permalink to &quot;3. Đang chạy thì nó bị văng ra (Crash)?&quot;">​</a></h3><p>Lúc này tính năng <strong>Healer 2.0 (AI Tự Chữa Lành)</strong> sẽ hoạt động. Mỗi khi TikTok thay đổi giao diện, thay vì phải gọi đội Dev sửa code, HappyAgent tự &quot;nhìn&quot; giao diện bằng AI, tìm hiểu nút bấm mới ở đâu và tự cập nhật cách bấm. Tất cả diễn ra tự động trong vòng 30 giây rưỡi! Việc của bạn là đợi AI tự khởi động lại.</p><h3 id="_4-bao-cao-toi-xem-o-đau" tabindex="-1">4. Báo cáo tôi xem ở đâu? <a class="header-anchor" href="#_4-bao-cao-toi-xem-o-đau" aria-label="Permalink to &quot;4. Báo cáo tôi xem ở đâu?&quot;">​</a></h3><p>Bạn sẽ có một Dashboard trực tiếp (Ngay trên máy tính của bạn) màu xanh mát mẻ báo rõ trạng thái: <strong>Bao nhiêu người đã nhận, Hôm nay hiệu suất làm việc ra sao</strong>.</p><hr><p>👉 <strong>Sẵn sàng chưa? Hãy xem hướng dẫn Cầm tay chỉ việc (Step-by-Step) tại trang tiếp theo để bấm chạy ngay lần đầu tiên!</strong></p>',23)])])}const d=h(o,[["render",e]]);export{u as __pageData,d as default};
